{
  "hooks": {
    "PostEditFile": [
      {
        "matcher": "**/*.{ts,tsx,js,jsx}",
        "command": "npx prettier --write $CLAUDE_FILE_PATH"
      },
      {
        "matcher": "**/*.{ts,tsx,js,jsx}",
        "command": "npx eslint --fix $CLAUDE_FILE_PATH"
      }
    ]
  }
}

{
  "hooks": {
    "Notification": [
      {
        "command": "osascript -e 'display notification \"$CLAUDE_NOTIFICATION\" with title \"Claude Code\"'"
      }
    ]
  }
}

{
  "hooks": {
    "Notification": [
      {
        "command": "curl -s -X POST $SLACK_WEBHOOK -d '{\"text\": \"Claude: $CLAUDE_NOTIFICATION\"}'"
      }
    ]
  }
}

{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "command": "echo $CLAUDE_TOOL_INPUT | grep -q 'rm.*\\.env' && exit 1 || exit 0"
      }
    ]
  }
}

{
  "hooks": {
    "PostEditFile": [
      {
        "matcher": "**/*.{ts,tsx,js,jsx,css,json,md}",
        "command": "npx prettier --write $CLAUDE_FILE_PATH"
      },
      {
        "matcher": "**/*.{ts,tsx,js,jsx}",
        "command": "npx eslint --fix $CLAUDE_FILE_PATH"
      }
    ],
    "Notification": [
      {
        "command": "echo \"[Claude] $CLAUDE_NOTIFICATION\" >> ~/claude-log.txt"
      }
    ]
  }
}
